# calculator.py
from __future__ import annotations
import math

OPERATIONS = ('Add', 'Subtract', 'Multiply', 'Divide')
SYMBOLS = {'Add': '+', 'Subtract': '\u2212', 'Multiply': '\u00d7', 'Divide': '\u00f7'}

class CalculatorError(ValueError):
    pass

def calculate(num1: float, num2: float, operation: str) -> tuple[float, str]:
    if operation not in OPERATIONS:
        raise CalculatorError(f'Unknown operation: {operation!r}')
    if operation == 'Divide' and num2 == 0.0:
        raise CalculatorError('Division by zero is not allowed.')
    ops = {
        'Add':      lambda a, b: a + b,
        'Subtract': lambda a, b: a - b,
        'Multiply': lambda a, b: a * b,
        'Divide':   lambda a, b: a / b,
    }
    result = ops[operation](num1, num2)
    if not math.isfinite(result):
        raise CalculatorError('Result is out of representable range (overflow).')
    return result, SYMBOLS[operation]

if operation == 'Add':
    result = num1 + num2
    symbol = '+'
elif operation == 'Subtract':
    result = num1 - num2
    symbol = '\u2212'  # U+2212 MINUS SIGN
elif operation == 'Multiply':
    result = num1 * num2
    symbol = '\u00d7'  # U+00D7 MULTIPLICATION SIGN
elif operation == 'Divide':
    symbol = '\u00f7'  # U+00F7 DIVISION SIGN
